# --- 1. Load Data and Initialize Model (Caches for Speed) ---
@st.cache_resource
def load_model():
    """Loads the Sentence-BERT model and corpus embeddings once."""
    model = SentenceTransformer('all-MiniLM-L6-v2')
    df = pd.read_csv('green_skill_chatbot.csv')
    corpus = df['text'].tolist()
    corpus_embeddings = model.encode(corpus, convert_to_tensor=True)
    return model, df, corpus_embeddings

model, df, corpus_embeddings = load_model()

