# --- 3. Chatbot Response Function ---
def get_chatbot_response_direct(user_query):
    query_embedding = model.encode(user_query, convert_to_tensor=True)
    cosine_scores = util.cos_sim(query_embedding, corpus_embeddings)[0]
    best_match_idx = torch.argmax(cosine_scores).item()

    # Get the original question that had the highest score
    most_similar_question = df.iloc[best_match_idx]['text']
    confidence_score = cosine_scores[best_match_idx].item()

    # Use the confidence score to decide if the answer is good enough
    if confidence_score > 0.6:  # Adjust this threshold as needed
        # Return the specific answer from the new dictionary
        return answers_dict.get(most_similar_question, "I couldn't find a precise answer.")
    else:
        return "I'm not sure I understand. Could you please rephrase?"

# --- 4. Streamlit UI Logic ---
st.set_page_config(
    page_title="Green Skills Chatbot",
    page_icon="🌱",
    layout="centered"
)

# Load the custom CSS file
def load_css(file_name):
    with open(file_name) as f:
        st.markdown(f'<style>{f.read()}</style>', unsafe_allow_html=True)

load_css('.streamlit/style.css') # Assuming your style.css is in a .streamlit folder

st.title("🌱 Green Skills Chatbot")
st.markdown("I'm here to answer your questions about green skills and sustainable practices.")

# Initialize chat history
if "messages" not in st.session_state:
    st.session_state.messages = []
    # Add a welcome message from the assistant
    st.session_state.messages.append({"role": "assistant", "content": random.choice(answers_dict['greeting'])})

# Display chat messages from history
for message in st.session_state.messages:
    with st.chat_message(message["role"]):
        # Add a class for styling
        st.markdown(f'<div class="chat-message-content">{message["content"]}</div>', unsafe_allow_html=True)

# React to user input
if prompt := st.chat_input("Ask me about sustainability..."):
    # Display user message in chat message container
    with st.chat_message("user"):
        st.markdown(prompt)
    # Add user message to chat history
    st.session_state.messages.append({"role": "user", "content": prompt})

    # Get and display assistant response
    response = get_chatbot_response_direct(prompt)
    with st.chat_message("assistant"):
        st.markdown(response)
    # Add assistant response to chat history
    st.session_state.messages.append({"role": "assistant", "content": response})